import{_ as e,c as n,o as a,a1 as o}from"./chunks/framework.DDNAyvCW.js";const r="/assets/terminal_tab.CFQwYZpn.png",p=JSON.parse('{"title":"Terminal Management","description":"","frontmatter":{},"headers":[],"relativePath":"docs/terminal/manage/index.md","filePath":"docs/terminal/manage/index.md"}'),s={name:"docs/terminal/manage/index.md"};function i(d,t,l,c,h,g){return a(),n("div",null,t[0]||(t[0]=[o('<h1 id="terminal-management" tabindex="-1">Terminal Management <a class="header-anchor" href="#terminal-management" aria-label="Permalink to &quot;Terminal Management&quot;">​</a></h1><p>Manage multiple terminal sessions, organize your workspace with tabs and splits, and keep your workflow efficient.</p><p><img src="'+r+'" alt=""></p><h2 id="tab-menu-bar-actions" tabindex="-1">Tab Menu Bar Actions <a class="header-anchor" href="#tab-menu-bar-actions" aria-label="Permalink to &quot;Tab Menu Bar Actions&quot;">​</a></h2><p>Right-click a tab or use the tab menu bar to access the following actions:</p><table tabindex="0"><thead><tr><th>Action</th><th>What It Does</th><th>When to Use It</th></tr></thead><tbody><tr><td><strong>Close</strong></td><td>Closes the current terminal session</td><td>When you are done with a task and no longer need the session</td></tr><tr><td><strong>Close Others</strong></td><td>Closes every session except the one currently focused</td><td>When your workspace is cluttered and you want to keep one session</td></tr><tr><td><strong>Close All</strong></td><td>Closes all open terminal sessions</td><td>When you are switching contexts or ending your work</td></tr><tr><td><strong>Clone</strong></td><td>Duplicates the current session into a new tab</td><td>When you need a second session on the same host</td></tr><tr><td><strong>Split Right</strong></td><td>Creates a horizontal split pane to the right</td><td>When you want side-by-side terminals (e.g., logs + commands)</td></tr><tr><td><strong>Split Down</strong></td><td>Creates a vertical split pane below</td><td>When you want stacked terminals (e.g., monitoring + operations)</td></tr></tbody></table><h2 id="right-click-menu-functions" tabindex="-1">Right-Click Menu Functions <a class="header-anchor" href="#right-click-menu-functions" aria-label="Permalink to &quot;Right-Click Menu Functions&quot;">​</a></h2><p>Right-click anywhere inside the terminal to access a context menu with the following options:</p><h3 id="basic-operations" tabindex="-1">Basic Operations <a class="header-anchor" href="#basic-operations" aria-label="Permalink to &quot;Basic Operations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Function</th><th>Description</th></tr></thead><tbody><tr><td><strong>Copy</strong></td><td>Copy the selected text to the clipboard</td></tr><tr><td><strong>Paste</strong></td><td>Paste clipboard content into the terminal</td></tr><tr><td><strong>Search</strong></td><td>Open the search bar to find text in the terminal output</td></tr><tr><td><strong>Clear</strong></td><td>Clear all visible output in the current terminal</td></tr><tr><td><strong>File Manager</strong></td><td>Open a file manager rooted at the terminal&#39;s working directory</td></tr><tr><td><strong>Font Size</strong></td><td>Scale the terminal font size up or down</td></tr></tbody></table><h3 id="connection-management" tabindex="-1">Connection Management <a class="header-anchor" href="#connection-management" aria-label="Permalink to &quot;Connection Management&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Function</th><th>Description</th></tr></thead><tbody><tr><td><strong>Disconnect</strong></td><td>Disconnect the current terminal&#39;s SSH connection</td></tr><tr><td><strong>New Terminal</strong></td><td>Open a brand-new terminal session</td></tr><tr><td><strong>Close Terminal</strong></td><td>Close the current terminal session</td></tr></tbody></table><h3 id="split-operations" tabindex="-1">Split Operations <a class="header-anchor" href="#split-operations" aria-label="Permalink to &quot;Split Operations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Function</th><th>Description</th></tr></thead><tbody><tr><td><strong>Split Right</strong></td><td>Create a horizontal split pane</td></tr><tr><td><strong>Split Down</strong></td><td>Create a vertical split pane</td></tr></tbody></table><h2 id="tips-for-managing-terminals" tabindex="-1">Tips for Managing Terminals <a class="header-anchor" href="#tips-for-managing-terminals" aria-label="Permalink to &quot;Tips for Managing Terminals&quot;">​</a></h2><ol><li><strong>Use splits for related tasks</strong> -- keep logs on one side and commands on the other. See <a href="/docs/terminal/operations/">Terminal Operations</a> for details on splitting.</li><li><strong>Rename tabs</strong> -- right-click a tab and rename it so you can quickly identify sessions.</li><li><strong>Close what you do not need</strong> -- unused sessions consume resources. Use <strong>Close Others</strong> or <strong>Close All</strong> to tidy up.</li><li><strong>Use AI to help</strong> -- let <a href="/docs/terminal/chattoai/">Chat to AI</a> generate commands so you can focus on results instead of syntax.</li></ol><div class="warning custom-block"><p class="custom-block-title">Important Notice</p><ul><li>Terminal operations require appropriate permissions on the remote host.</li><li>Always review commands before executing them, especially on production servers.</li><li>Verify risky operations in a test environment first.</li></ul></div>',17)]))}const u=e(s,[["render",i]]);export{p as __pageData,u as default};
